import java.util.Scanner;

public class SafeBufferCopy {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensure that the buffer size matches the input string length or use a dynamic resizing strategy
        char[] buffer = new char[name.length()];

        // Perform safe copying by limiting the number of characters to copy
        int copyLength = Math.min(name.length(), buffer.length);
        name.getChars(0, copyLength, buffer, 0);

        System.out.println("Buffer content: " + new String(buffer));
    }
}

